Source2
#include &lt;stdio.h&gt; #define R1 2 #define C1 3 #define R2 3 #define C2 2 static inline void matmul1(int A[R1][C1], int B[R2][C2], int C[R1][C2]) { for (int i = 0; i &lt; R1; i++) { for (int j = 0; j &lt; C2; j++) { C[i][j] = 0; for (int k = 0; k &lt; C1; k++) { C[i][j] += A[i][k] * B[k][j]; } } } } int main() { int A[R1][C1] = {{1, 2, 2}, {3, 3, 4}}; int B[R2][C2] = {{1, 2}, {2, 3}, {3, 4}}; int C[R1][C2]; matmul1(A, B, C); for (int i = 0; i &lt; R1; i++) { for (int j = 0; j &lt; C2; j++) { printf(&#34;%d &#34;, C[i][j]); } printf(&#34;\n&#34;); } return 0; } 2D malloc # #include &lt;stdio.h&gt; #include &lt;stdlib.h&gt; void matmul2(int **A, int **B, int **C, int R1, int C1, int C2) { for (int i = 0; i &lt; R1; i++) { for (int j = 0; j &lt; C2; j++) { C[i][j] = 0; for (int k = 0; k &lt; C1; k++) { C[i][j] += A[i][k] * B[k][j]; } } } } int main() { int R1 = 2, C1 = 3, R2 = 3, C2 = 2; int **A = malloc(R1 * sizeof(int *)); int **B = malloc(R2 * sizeof(int *)); int **C = malloc(R1 * sizeof(int *)); for (int i = 0; i &lt; R1; i++) A[i] = malloc(C1 * sizeof(int)); for (int i = 0; i &lt; R2; i++) B[i] = malloc(C2 * sizeof(int)); for (int i = 0; i &lt; R1; i++) C[i] = malloc(C2 * sizeof(int)); int tempA[2][3] = {{1, 2, 2}, {3, 3, 4}}; int tempB[3][2] = {{1, 2}, {2, 3}, {3, 4}}; for (int i = 0; i &lt; R1; i++) for (int j = 0; j &lt; C1; j++) A[i][j] = tempA[i][j]; for (int i = 0; i &lt; R2; i++) for (int j = 0; j &lt; C2; j++) B[i][j] = tempB[i][j]; matmul2(A, B, C, R1, C1, C2); for (int i = 0; i &lt; R1; i++) { for (int j = 0; j &lt; C2; j++) { printf(&#34;%d &#34;, C[i][j]); } printf(&#34;\n&#34;); } for (int i = 0; i &lt; R1; i++) free(A[i]); for (int i = 0; i &lt; R2; i++) free(B[i]); for (int i = 0; i &lt; R1; i++) free(C[i]); free(A); free(B); free(C); return 0; } 1D array 模擬 2D array # #include &lt;stdio.h&gt; #include &lt;stdlib.h&gt; void matmul3(int *A, int *B, int *C, int R1, int C1, int C2) { for (int i = 0; i &lt; R1; i++) { for (int j = 0; j &lt; C2; j++) { C[i * C2 + j] = 0; for (int k = 0; k &lt; C1; k++) { C[i * C2 + j] += A[i * C1 + k] * B[k * C2 + j]; } } } } int main() { int R1 = 2, C1 = 3, R2 = 3, C2 = 2; int A[] = {1, 2, 2, 3, 3, 4}; int B[] = {1, 2, 2, 3, 3, 4}; int C[R1 * C2]; matmul3(A, B, C, R1, C1, C2); for (int i = 0; i &lt; R1; i++) { for (int j = 0; j &lt; C2; j++) { printf(&#34;%d &#34;, C[i * C2 + j]); } printf(&#34;\n&#34;); } return 0; }

 快速看完 # 看完這張圖這篇文章就不用看了。 正文 # 最近用WebP轉存圖片轉得很開心，壓二次元圖隨便都是80%以上壓縮率，現在來關心一下他的解碼性能。
根據 Google Group 上的討論1， WebP 的解碼速度是弱於 JPG 的，畢竟 JPG 都已經發展這麼久了軟硬體都已經很成熟。這麼說來 WebP 除了壓縮率以外沒有優勢嗎？並不是， WebP 是為了網路而生，把下載時間也算進來整體載入速度是提高的，如果有增量解碼載入速度提升更多。
至於轉換品質，這裡有一個懶人包2的設定，簡單來說8085是一個甜蜜點。
(註：不過請注意此專案沒有給出 AVIF 的單位映射，AVIF quality 為063，他把全部都換成1~100了，而且使用DSSIM而非常見的SSIM作為指標，除此之外根據圖片不同可能轉了之後反而容量更大)
其實這應該是第二篇，第一篇是各種次世代編碼的選擇，不過這篇資料都在手上就先寫出來了。最後34是其他評測。
